<div x-data="{ visible: false, message: '', timer: null }" x-on:toast.window="message = $event.detail.message; visible = true; clearTimeout(timer); timer = setTimeout(() => visible = false, 4500)" x-show="visible" x-transition class="fixed right-5 top-5 z-50 max-w-sm rounded-xl border border-emerald-400/30 bg-slate-900 px-5 py-4 text-sm font-medium text-white shadow-2xl" style="display:none"><span x-text="message"></span></div>
